(function () {
  if (typeof window === "undefined") {
    return;
  }

  function escapeHTML(value) {
    return String(value || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function stripDelimiters(value) {
    var trimmed = String(value || "").replace(/^\s+|\s+$/g, "");
    if (trimmed.slice(0, 2) === "$$" && trimmed.slice(-2) === "$$") {
      return trimmed.slice(2, -2).replace(/^\s+|\s+$/g, "");
    }
    if (trimmed.charAt(0) === "$" && trimmed.charAt(trimmed.length - 1) === "$") {
      return trimmed.slice(1, -1).replace(/^\s+|\s+$/g, "");
    }
    return trimmed;
  }

  function formatExpression(raw) {
    var output = escapeHTML(raw)
      .replace(/\r?\n+/g, " ")
      .replace(/\s+/g, " ")
      .replace(/\\left/g, "")
      .replace(/\\right/g, "")
      .replace(/\\,/g, " ")
      .replace(/\\!/g, "")
      .replace(/\\frac\{([^{}]+)\}\{([^{}]+)\}/g, '<span class="math-frac"><span class="math-frac-num">$1</span><span class="math-frac-den">$2</span></span>')
      .replace(/\\times/g, "&times;")
      .replace(/\\cdot/g, "&middot;")
      .replace(/\\leq/g, "&le;")
      .replace(/\\geq/g, "&ge;")
      .replace(/\\neq/g, "&ne;")
      .replace(/\\rightarrow|\\to/g, "&rarr;")
      .replace(/\\leftarrow/g, "&larr;")
      .replace(/\\infty/g, "&infin;")
      .replace(/\\pm/g, "&plusmn;")
      .replace(/\\sum/g, "&sum;")
      .replace(/\\prod/g, "&prod;")
      .replace(/\\alpha/g, "&alpha;")
      .replace(/\\beta/g, "&beta;")
      .replace(/\\gamma/g, "&gamma;")
      .replace(/\\theta/g, "&theta;")
      .replace(/\\pi/g, "&pi;");

    output = output
      .replace(/(&[A-Za-z]+;|[A-Za-z0-9)\]])\^\{([^{}]+)\}/g, "$1<sup>$2</sup>")
      .replace(/(&[A-Za-z]+;|[A-Za-z0-9)\]])\^([A-Za-z0-9+\-])/g, "$1<sup>$2</sup>")
      .replace(/(&[A-Za-z]+;|[A-Za-z0-9)\]])_\{([^{}]+)\}/g, "$1<sub>$2</sub>")
      .replace(/(&[A-Za-z]+;|[A-Za-z0-9)\]])_([A-Za-z0-9+\-])/g, "$1<sub>$2</sub>");

    return output.replace(/^\s+|\s+$/g, "");
  }

  function buildMarkup(value, options) {
    var raw = stripDelimiters(value);
    if (!raw) {
      return "";
    }

    var displayMode = !!(options && options.displayMode);
    var content = '<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><mtext>' + escapeHTML(raw) + '</mtext></math></span><span class="katex-html" aria-hidden="true"><span class="base">' + formatExpression(raw) + "</span></span></span>";
    if (displayMode) {
      return '<span class="katex-display">' + content + "</span>";
    }
    return content;
  }

  window.katex = {
    render: function (value, element, options) {
      if (!element) {
        return;
      }
      element.innerHTML = buildMarkup(value, options);
    },
    renderToString: function (value, options) {
      return buildMarkup(value, options);
    }
  };
})();